#include<bits/stdc++.h>
using namespace std;
int n,ant,f;
bool v[1000010];
struct a{
    int a,b;
};
bool cmp(a a1,a a2){
    return a1.b<a2.b;
}

int main(){
    cin>>n;
    a b[n+1];
    for(int i=1;i<=n;i++){
        cin>>b[i].a>>b[i].b;
    }
    sort(b+1,b+n+1,cmp);
    for(int i=1;i<=n;i++){
        if(f<=b[i].a){
            ant++;
            f=b[i].b;
        }
    }
    cout<<ant;
}
